toolCalls.args:
{"command": "DBG=/tmp/symbols/libmonosgen-2.0.so.debug
# Use readelf to find function symbols spanning these addresses
aarch64-linux-gnu-readelf -Ws "$DBG" 2>/dev/null | awk '
$4 == "FUNC" {
    addr = strtonum("0x"$2)
    size = strtonum("0x"$3)
    if (addr <= 0x2f4b20 && (addr+size) > 0x2f4b20) print "0x2f4b20 in:", $0
    if (addr <= 0x2f4c84 && (addr+size) > 0x2f4c84) print "0x2f4c84 in:", $0
}'", "description": "Find function symbols via readelf", "initial_wait": 15}

arguments.command:
DBG=/tmp/symbols/libmonosgen-2.0.so.debug
# Find the nearest symbols using nm sorted by address
aarch64-linux-gnu-nm -n -S "$DBG" 2>/dev/null | awk '{
    addr = strtonum("0x"$1)
    if (addr <= 0x2f4b20) { before_b20 = $0; addr_before_b20 = addr }
    if (addr > 0x2f4b20 && !after_b20) { after_b20 = $0 }
    if (addr <= 0x2f4c84) { before_c84 = $0; addr_before_c84 = addr }
    if (addr > 0x2f4c84 && !after_c84) { after_c84 = $0 }
}
END {
    print "0x2f4b20 between:"
    print "  before:", before_b20, "(offset +" sprintf("0x%x", 0x2f4b20 - addr_before_b20) ")"
    print "  after: ", after_b20
    print ""
    print "0x2f4c84 between:"
    print "  before:", before_c84, "(offset +" sprintf("0x%x", 0x2f4c84 - addr_before_c84) ")"
    print "  after: ", after_c84
}'

